<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Conway's Game of Life</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body {
    background: #0d1117;
    color: #c9d1d9;
    font-family: 'Segoe UI', system-ui, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    overflow: hidden;
  }
  h1 {
    font-size: 1.6rem;
    margin-bottom: 12px;
    color: #58a6ff;
    text-shadow: 0 0 20px rgba(88,166,255,0.3);
    letter-spacing: 1px;
  }
  #controls {
    display: flex;
    gap: 10px;
    margin-bottom: 14px;
    flex-wrap: wrap;
    justify-content: center;
  }
  #controls button {
    padding: 8px 20px;
    border: 1px solid #30363d;
    border-radius: 8px;
    background: #161b22;
    color: #c9d1d9;
    font-size: 0.95rem;
    cursor: pointer;
    transition: all 0.15s ease;
    font-weight: 600;
    letter-spacing: 0.5px;
  }
  #controls button:hover {
    background: #21262d;
    border-color: #58a6ff;
    color: #58a6ff;
    box-shadow: 0 0 12px rgba(88,166,255,0.15);
  }
  #controls button:active {
    transform: scale(0.96);
  }
  #controls button.active {
    background: #1f6feb;
    border-color: #58a6ff;
    color: #fff;
    box-shadow: 0 0 16px rgba(31,111,235,0.4);
  }
  #life {
    border: 2px solid #30363d;
    border-radius: 6px;
    cursor: crosshair;
    background: #010409;
    box-shadow: 0 0 40px rgba(0,0,0,0.6), inset 0 0 60px rgba(0,0,0,0.3);
    image-rendering: pixelated;
  }
  #info {
    margin-top: 12px;
    font-size: 0.8rem;
    color: #484f58;
    text-align: center;
  }
  #generation {
    color: #58a6ff;
    font-weight: 600;
  }
</style>
</head>
<body>
<h1>🧬 Game of Life</h1>
<div id="controls">
  <button id="step">⏭ Step</button>
  <button id="play">▶ Play</button>
  <button id="random">🎲 Random</button>
  <button id="clear">💀 Clear</button>
</div>
<canvas id="life"></canvas>
<div id="info">Generation: <span id="generation">0</span> &nbsp;|&nbsp; Click &amp; drag to paint cells</div>

<script>
(function() {
  // Grid dimensions (>= 40 each)
  const W = 50;
  const H = 50;
  const CELL_SIZE = 10;
  const CANVAS_SIZE = W * CELL_SIZE; // 500px >= 400px

  // State arrays
  let grid = new Uint8Array(W * H);
  let nextGrid = new Uint8Array(W * H);
  let generation = 0;
  let playing = false;
  let animFrameId = null;
  let lastStepTime = 0;
  const STEP_INTERVAL = 120; // ms between auto-run steps

  // Canvas setup
  const canvas = document.getElementById('life');
  const ctx = canvas.getContext('2d');
  canvas.width = CANVAS_SIZE;
  canvas.height = CANVAS_SIZE;
  canvas.style.width = CANVAS_SIZE + 'px';
  canvas.style.height = CANVAS_SIZE + 'px';

  // DOM refs
  const stepBtn = document.getElementById('step');
  const playBtn = document.getElementById('play');
  const randomBtn = document.getElementById('random');
  const clearBtn = document.getElementById('clear');
  const genSpan = document.getElementById('generation');

  // --- Grid API ---
  function getCell(x, y) {
    if (x < 0 || x >= W || y < 0 || y >= H) return 0;
    return grid[y * W + x];
  }

  function setCell(x, y, v) {
    if (x < 0 || x >= W || y < 0 || y >= H) return;
    grid[y * W + x] = v ? 1 : 0;
  }

  function countNeighbors(x, y) {
    let count = 0;
    for (let dy = -1; dy <= 1; dy++) {
      for (let dx = -1; dx <= 1; dx++) {
        if (dx === 0 && dy === 0) continue;
        count += getCell(x + dx, y + dy);
      }
    }
    return count;
  }

  function step() {
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        const idx = y * W + x;
        const n = countNeighbors(x, y);
        const alive = grid[idx];
        if (alive) {
          nextGrid[idx] = (n === 2 || n === 3) ? 1 : 0;
        } else {
          nextGrid[idx] = (n === 3) ? 1 : 0;
        }
      }
    }
    // Swap grids
    let tmp = grid;
    grid = nextGrid;
    nextGrid = tmp;
    generation++;
    genSpan.textContent = generation;
    draw();
  }

  function clear() {
    grid.fill(0);
    generation = 0;
    genSpan.textContent = 0;
    draw();
  }

  function randomize() {
    for (let i = 0; i < grid.length; i++) {
      grid[i] = Math.random() < 0.3 ? 1 : 0;
    }
    draw();
  }

  // --- Rendering ---
  function draw() {
    ctx.fillStyle = '#010409';
    ctx.fillRect(0, 0, CANVAS_SIZE, CANVAS_SIZE);

    // Draw grid lines (subtle)
    ctx.strokeStyle = '#161b22';
    ctx.lineWidth = 0.5;
    for (let x = 0; x <= W; x++) {
      ctx.beginPath();
      ctx.moveTo(x * CELL_SIZE, 0);
      ctx.lineTo(x * CELL_SIZE, CANVAS_SIZE);
      ctx.stroke();
    }
    for (let y = 0; y <= H; y++) {
      ctx.beginPath();
      ctx.moveTo(0, y * CELL_SIZE);
      ctx.lineTo(CANVAS_SIZE, y * CELL_SIZE);
      ctx.stroke();
    }

    // Draw alive cells
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        if (grid[y * W + x]) {
          // Gradient fill for visual appeal
          const px = x * CELL_SIZE;
          const py = y * CELL_SIZE;
          ctx.fillStyle = '#58a6ff';
          ctx.fillRect(px + 1, py + 1, CELL_SIZE - 2, CELL_SIZE - 2);

          // Glow effect
          ctx.fillStyle = 'rgba(88, 166, 255, 0.15)';
          ctx.fillRect(px, py, CELL_SIZE, CELL_SIZE);
        }
      }
    }
  }

  // --- Auto-run ---
  function autoRun(timestamp) {
    if (!playing) return;
    if (timestamp - lastStepTime >= STEP_INTERVAL) {
      step();
      lastStepTime = timestamp;
    }
    animFrameId = requestAnimationFrame(autoRun);
  }

  function togglePlay() {
    playing = !playing;
    if (playing) {
      playBtn.textContent = '⏸ Pause';
      playBtn.classList.add('active');
      lastStepTime = performance.now();
      animFrameId = requestAnimationFrame(autoRun);
    } else {
      playBtn.textContent = '▶ Play';
      playBtn.classList.remove('active');
      if (animFrameId) {
        cancelAnimationFrame(animFrameId);
        animFrameId = null;
      }
    }
  }

  // --- Click / Drag painting ---
  let painting = false;
  let paintValue = 1;

  function getCellFromEvent(e) {
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    const x = Math.floor((e.clientX - rect.left) * scaleX / CELL_SIZE);
    const y = Math.floor((e.clientY - rect.top) * scaleY / CELL_SIZE);
    return { x, y };
  }

  function paintCell(x, y) {
    if (x >= 0 && x < W && y >= 0 && y < H) {
      grid[y * W + x] = paintValue;
      draw();
    }
  }

  canvas.addEventListener('mousedown', function(e) {
    e.preventDefault();
    painting = true;
    const { x, y } = getCellFromEvent(e);
    paintValue = grid[y * W + x] ? 0 : 1;
    paintCell(x, y);
  });

  canvas.addEventListener('mousemove', function(e) {
    if (!painting) return;
    e.preventDefault();
    const { x, y } = getCellFromEvent(e);
    paintCell(x, y);
  });

  canvas.addEventListener('mouseup', function() { painting = false; });
  canvas.addEventListener('mouseleave', function() { painting = false; });

  // Touch support
  canvas.addEventListener('touchstart', function(e) {
    e.preventDefault();
    painting = true;
    const touch = e.touches[0];
    const { x, y } = getCellFromEvent(touch);
    paintValue = grid[y * W + x] ? 0 : 1;
    paintCell(x, y);
  }, { passive: false });

  canvas.addEventListener('touchmove', function(e) {
    e.preventDefault();
    if (!painting) return;
    const touch = e.touches[0];
    const { x, y } = getCellFromEvent(touch);
    paintCell(x, y);
  }, { passive: false });

  canvas.addEventListener('touchend', function() { painting = false; });

  // --- Button handlers ---
  stepBtn.addEventListener('click', function() {
    step();
  });

  playBtn.addEventListener('click', function() {
    togglePlay();
  });

  randomBtn.addEventListener('click', function() {
    randomize();
  });

  clearBtn.addEventListener('click', function() {
    clear();
    if (playing) togglePlay();
  });

  // --- Expose API on window ---
  window.life = {
    get w() { return W; },
    get h() { return H; },
    get: getCell,
    set: setCell,
    step: step,
    clear: clear
  };

  // Initial draw
  draw();
})();
</script>
</body>
</html>
